            background-color: #ff9800;
            color: white;
        }
        .operator:hover {
            background-color: #f57c00;
        }
        .equal {
            background-color: #4caf50;
            color: white;
            grid-column: span 2;
        }
        .equal:hover {
            background-color: #45a049;
        }
        .clear {
            background-color: #f44336;
            color: white;
        }
