        function appendNumber(num) {
            if (num === '.' && currentInput.includes('.')) return;
            currentInput += num;
            updateDisplay(currentInput);
        }

        function setOperator(op) {
            if (currentInput === '' && previousInput === '') return;

            // Jika sudah ada current input dan previous input, hitung dulu
            if (previousInput !== '' && currentInput !== '') {
                calculate();
            }

            operator = op;

            // Jika currentInput kosong (setelah calculate), previousInput sudah terisi hasil
            if (currentInput !== '') {
                previousInput = currentInput;
            }
            currentInput = '';

            // Tandai tombol operator yang aktif
            removeActiveOperatorClass();
            const activeBtnId = operatorButtonMap[op];
            if (activeBtnId) {
