            let result;
            const prev = parseFloat(previousInput);
            const curr = parseFloat(currentInput);

            switch (operator) {
                case '+':
                    result = prev + curr;
                    break;
                case '-':
                    result = prev - curr;
                    break;
                case '*':
                    result = prev * curr;
                    break;
                case '/':
                    if (curr === 0) {
                        alert('Pembagian dengan nol tidak diperbolehkan');
                        clearDisplay();
                        return;
                    }
                    result = prev / curr;
                    break;
                default:
                    return;
            }

            // Hapus highlight operator setelah perhitungan
            removeActiveOperatorClass();

            currentInput = result.toString();
            previousInput = '';
            operator = null;
            updateDisplay(currentInput);
            updateOperatorIndicator();
        }

        function clearDisplay() {
            currentInput = '';
            previousInput = '';
            operator = null;
            removeActiveOperatorClass();
            updateDisplay('');
            updateOperatorIndicator();
        }

        function updateDisplay(value) {
            document.getElementById('display').value = value;
        }
